"""
Represents the checkers board.
"""

import numpy as np

class Piece:
    def __init__(self, color):
        self.color = color  # 'R' for red, 'B' for black
        self.is_king = False

    def make_king(self):
        self.is_king = True

class Board:
    def __init__(self):
        self.board = np.array([[None] * 8 for _ in range(8)])
        self.setup_board()

    def setup_board(self):
        # Place the initial pieces
        for i in range(3):
            for j in range((i + 1) % 2, 8, 2):
                self.board[i][j] = Piece('R')
        for i in range(5, 8):
            for j in range(i % 2, 8, 2):
                self.board[i][j] = Piece('B')

    def print_board(self):
        for row in self.board:
            print(" ".join([str(piece) if piece else '.' for piece in row]))

    def move_piece(self, from_pos, to_pos):
        from_x, from_y = from_pos
        to_x, to_y = to_pos
        piece = self.board[from_x][from_y]
        self.board[from_x][from_y] = None
        if abs(to_x - from_x) == 2:  # Capture move
            self.capture(from_x + (to_x - from_x) // 2, from_y + (to_y - from_y) // 2)
        self.board[to_x][to_y] = piece

    def capture(self, x, y):
        if self.board[x][y]:
            del self.board[x][y]

if __name__ == "__main__":
    board = Board()
    board.print_board()
```

